```typescript
export type CodeReviewState =
  | { status: "none" }
  | { status: "requested"; id: string; author: string; reviewers: string[] }
  | { status: "inProgress"; id: string; comments: number }
  | { status: "completed"; id: string; verdict: "approve" | "changes" };

export type CodeReviewCommand =
  | { type: "request"; id: string; author: string; reviewers: string[] }
  | { type: "comment"; text: string }
  | { type: "submit"; verdict: "approve" | "changes" };

export type CodeReviewEvent =
  | { type: "CodeReviewRequested"; id: string; author: string; reviewers: string[] }
  | { type: "CodeReviewCommented"; text: string }
  | { type: "CodeReviewSubmitted"; verdict: "approve" | "changes" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): CodeReviewEvent[];
  evolve(state: S, event: E): S;
}

export const codeReviewDecider: Decider<CodeReviewCommand, CodeReviewEvent, CodeReviewState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "request":
        if (state.status !== "none") throw new DomainError("ALREADY_REQUESTED");
        if (command.reviewers.length === 0) throw new DomainError("NO_REVIEWERS");
        return [{ type: "CodeReviewRequested", id: command.id, author: command.author, reviewers: command.reviewers }];
      case "comment":
        if (state.status === "none") throw new DomainError("NOT_REQUESTED");
        if (state.status === "completed") throw new DomainError("ALREADY_COMPLETED");
        return [{ type: "CodeReviewCommented", text: command.text }];
      case "submit":
        if (state.status === "completed") throw new DomainError("ALREADY_COMPLETED");
        if (state.status === "none") throw new DomainError("NOT_REQUESTED");
        return [{ type: "CodeReviewSubmitted", verdict: command.verdict }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CodeReviewRequested":
        return { status: "requested", id: event.id, author: event.author, reviewers: event.reviewers };
      case "CodeReviewCommented":
        if (state.status === "requested") return { status: "inProgress", id: state.id, comments: 1 };
        if (state.status === "inProgress") return { ...state, comments: state.comments + 1 };
        return state;
      case "CodeReviewSubmitted":
        if (state.status === "none" || state.status === "completed") return state;
        return { status: "completed", id: state.id, verdict: event.verdict };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

A Decider packages three pure functions: an initialState literal, a decide that maps (command, state) -> events or throws on invariant violations, and an evolve that folds events back into state. The BuildRun aggregate has a simple lifecycle: started -> (succeeded | failed). Invariants: cannot start twice, cannot finish or fail a run that is not running.

```typescript
export type BuildRunState =
  | { status: "none" }
  | { status: "running"; id: string; commit: string; startedAt: string }
  | { status: "succeeded"; id: string; finishedAt: string; artefactId: string }
  | { status: "failed"; id: string; finishedAt: string; reason: string };

export type BuildRunCommand =
  | { type: "start"; id: string; commit: string; at: string }
  | { type: "finish"; at: string; artefactId: string }
  | { type: "fail"; at: string; reason: string };

export type BuildRunEvent =
  | { type: "BuildRunStarted"; id: string; commit: string; at: string }
  | { type: "BuildRunFinished"; at: string; artefactId: string }
  | { type: "BuildRunFailed"; at: string; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const buildRunDecider: Decider<BuildRunCommand, BuildRunEvent, BuildRunState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "start":
        if (state.status !== "none") throw new DomainError("ALREADY_STARTED");
        return [{ type: "BuildRunStarted", id: command.id, commit: command.commit, at: command.at }];
      case "finish":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "BuildRunFinished", at: command.at, artefactId: command.artefactId }];
      case "fail":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "BuildRunFailed", at: command.at, reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "BuildRunStarted":
        return { status: "running", id: event.id, commit: event.commit, startedAt: event.at };
      case "BuildRunFinished":
        if (state.status !== "running") return state;
        return { status: "succeeded", id: state.id, finishedAt: event.at, artefactId: event.artefactId };
      case "BuildRunFailed":
        if (state.status !== "running") return state;
        return { status: "failed", id: state.id, finishedAt: event.at, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
