```typescript
export type TestSuiteState =
  | { status: "none" }
  | { status: "registered"; id: string; name: string; testCount: number }
  | { status: "running"; id: string; name: string; runId: string; startedAt: string }
  | { status: "reported"; id: string; runId: string; passed: number; failed: number };

export type TestSuiteCommand =
  | { type: "register"; id: string; name: string; testCount: number }
  | { type: "run"; runId: string; at: string }
  | { type: "report"; passed: number; failed: number };

export type TestSuiteEvent =
  | { type: "TestSuiteRegistered"; id: string; name: string; testCount: number }
  | { type: "TestSuiteRunStarted"; runId: string; at: string }
  | { type: "TestSuiteResultReported"; passed: number; failed: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const testSuiteDecider: Decider<TestSuiteCommand, TestSuiteEvent, TestSuiteState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("ALREADY_REGISTERED");
        if (command.testCount <= 0) throw new DomainError("EMPTY_SUITE");
        return [{ type: "TestSuiteRegistered", id: command.id, name: command.name, testCount: command.testCount }];
      case "run":
        if (state.status !== "registered") throw new DomainError("NOT_REGISTERED");
        return [{ type: "TestSuiteRunStarted", runId: command.runId, at: command.at }];
      case "report":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (command.passed < 0 || command.failed < 0) throw new DomainError("BAD_COUNTS");
        return [{ type: "TestSuiteResultReported", passed: command.passed, failed: command.failed }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TestSuiteRegistered":
        return { status: "registered", id: event.id, name: event.name, testCount: event.testCount };
      case "TestSuiteRunStarted":
        if (state.status !== "registered") return state;
        return { status: "running", id: state.id, name: state.name, runId: event.runId, startedAt: event.at };
      case "TestSuiteResultReported":
        if (state.status !== "running") return state;
        return { status: "reported", id: state.id, runId: state.runId, passed: event.passed, failed: event.failed };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
