```typescript
export type FeatureBranchState =
  | { status: "none" }
  | { status: "active"; name: string; base: string; commits: number; lastPushedAt?: string }
  | { status: "deleted"; name: string; deletedAt: string };

export type FeatureBranchCommand =
  | { type: "create"; name: string; base: string }
  | { type: "push"; sha: string; at: string }
  | { type: "rebase"; onto: string; at: string }
  | { type: "delete"; at: string };

export type FeatureBranchEvent =
  | { type: "FeatureBranchCreated"; name: string; base: string }
  | { type: "FeatureBranchPushed"; sha: string; at: string }
  | { type: "FeatureBranchRebased"; onto: string; at: string }
  | { type: "FeatureBranchDeleted"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const featureBranchDecider: Decider<FeatureBranchCommand, FeatureBranchEvent, FeatureBranchState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("ALREADY_EXISTS");
        return [{ type: "FeatureBranchCreated", name: command.name, base: command.base }];
      case "push":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "FeatureBranchPushed", sha: command.sha, at: command.at }];
      case "rebase":
        if (state.status === "deleted") throw new DomainError("ALREADY_DELETED");
        if (state.status === "none") throw new DomainError("NOT_FOUND");
        return [{ type: "FeatureBranchRebased", onto: command.onto, at: command.at }];
      case "delete":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "FeatureBranchDeleted", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FeatureBranchCreated":
        return { status: "active", name: event.name, base: event.base, commits: 0 };
      case "FeatureBranchPushed":
        if (state.status !== "active") return state;
        return { ...state, commits: state.commits + 1, lastPushedAt: event.at };
      case "FeatureBranchRebased":
        if (state.status !== "active") return state;
        return { ...state, base: event.onto };
      case "FeatureBranchDeleted":
        if (state.status !== "active") return state;
        return { status: "deleted", name: state.name, deletedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
