```typescript
export type ArtefactState =
  | { status: "none" }
  | { status: "published"; id: string; sha256: string; sizeBytes: number; signed: boolean }
  | { status: "retracted"; id: string; reason: string };

export type ArtefactCommand =
  | { type: "publish"; id: string; sha256: string; sizeBytes: number }
  | { type: "sign"; signer: string }
  | { type: "retract"; reason: string };

export type ArtefactEvent =
  | { type: "ArtefactPublished"; id: string; sha256: string; sizeBytes: number }
  | { type: "ArtefactSigned"; signer: string }
  | { type: "ArtefactRetracted"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const artefactDecider: Decider<ArtefactCommand, ArtefactEvent, ArtefactState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "publish":
        if (state.status !== "none") throw new DomainError("ALREADY_PUBLISHED");
        if (command.sizeBytes <= 0) throw new DomainError("EMPTY_ARTEFACT");
        return [{ type: "ArtefactPublished", id: command.id, sha256: command.sha256, sizeBytes: command.sizeBytes }];
      case "sign":
        if (state.status === "retracted") throw new DomainError("RETRACTED");
        if (state.status === "none") throw new DomainError("NOT_PUBLISHED");
        if (state.signed) throw new DomainError("ALREADY_SIGNED");
        return [{ type: "ArtefactSigned", signer: command.signer }];
      case "retract":
        if (state.status !== "published") throw new DomainError("NOT_PUBLISHED");
        return [{ type: "ArtefactRetracted", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ArtefactPublished":
        return { status: "published", id: event.id, sha256: event.sha256, sizeBytes: event.sizeBytes, signed: false };
      case "ArtefactSigned":
        if (state.status !== "published") return state;
        return { ...state, signed: true };
      case "ArtefactRetracted":
        if (state.status !== "published") return state;
        return { status: "retracted", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
