```typescript
export type PullRequestEvent =
  | { type: "PullRequestOpened"; id: string; branch: string; author: string; at: string }
  | { type: "PullRequestApproved"; id: string; reviewer: string }
  | { type: "PullRequestMerged"; id: string; at: string }
  | { type: "PullRequestClosed"; id: string; reason: string };

export interface OpenPullRequestRow {
  readonly id: string;
  readonly branch: string;
  readonly author: string;
  readonly openedAt: string;
  readonly approvals: number;
}

export interface DashboardView {
  readonly open: Record<string, OpenPullRequestRow>;
  readonly mergedCount: number;
  readonly closedCount: number;
}

export const emptyView: DashboardView = { open: {}, mergedCount: 0, closedCount: 0 };

export function project(view: DashboardView, event: PullRequestEvent): DashboardView {
  switch (event.type) {
    case "PullRequestOpened": {
      const row: OpenPullRequestRow = {
        id: event.id,
        branch: event.branch,
        author: event.author,
        openedAt: event.at,
        approvals: 0,
      };
      return { ...view, open: { ...view.open, [event.id]: row } };
    }
    case "PullRequestApproved": {
      const current = view.open[event.id];
      if (!current) return view;
      const updated: OpenPullRequestRow = { ...current, approvals: current.approvals + 1 };
      return { ...view, open: { ...view.open, [event.id]: updated } };
    }
    case "PullRequestMerged": {
      if (!view.open[event.id]) return view;
      const { [event.id]: _removed, ...rest } = view.open;
      return { ...view, open: rest, mergedCount: view.mergedCount + 1 };
    }
    case "PullRequestClosed": {
      if (!view.open[event.id]) return view;
      const { [event.id]: _removed, ...rest } = view.open;
      return { ...view, open: rest, closedCount: view.closedCount + 1 };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
```

A projection folds a subset of domain events into a flat read model. Keep it pure and ignore events outside the view's interest.

```typescript
export type BuildRunEvent =
  | { type: "BuildRunStarted"; commit: string; runId: string; at: string }
  | { type: "BuildRunFinished"; runId: string; commit: string; at: string; artefactId: string }
  | { type: "BuildRunFailed"; runId: string; commit: string; at: string; reason: string };

export interface CommitStats {
  readonly total: number;
  readonly succeeded: number;
  readonly failed: number;
}

export interface BuildStatsView {
  readonly perCommit: Record<string, CommitStats>;
}

export const emptyView: BuildStatsView = { perCommit: {} };

function bump(view: BuildStatsView, commit: string, patch: Partial<CommitStats>): BuildStatsView {
  const existing = view.perCommit[commit] ?? { total: 0, succeeded: 0, failed: 0 };
  const next: CommitStats = {
    total: existing.total + (patch.total ?? 0),
    succeeded: existing.succeeded + (patch.succeeded ?? 0),
    failed: existing.failed + (patch.failed ?? 0),
  };
  return { perCommit: { ...view.perCommit, [commit]: next } };
}

export function project(view: BuildStatsView, event: BuildRunEvent): BuildStatsView {
  switch (event.type) {
    case "BuildRunStarted":
      return bump(view, event.commit, { total: 1 });
    case "BuildRunFinished":
      return bump(view, event.commit, { succeeded: 1 });
    case "BuildRunFailed":
      return bump(view, event.commit, { failed: 1 });
    default: {
      const _never: never = event;
      return view;
    }
  }
}
