```typescript
export type FeatureBranchEvent =
  | { type: "FeatureBranchCreated"; name: string; base: string }
  | { type: "FeatureBranchPushed"; name: string; sha: string; at: string }
  | { type: "FeatureBranchRebased"; name: string; onto: string; at: string }
  | { type: "FeatureBranchDeleted"; name: string; at: string };

export interface BranchStat {
  readonly name: string;
  readonly pushes: number;
  readonly lastPushAt?: string;
  readonly active: boolean;
}

export interface LeaderboardView {
  readonly branches: Record<string, BranchStat>;
}

export const emptyView: LeaderboardView = { branches: {} };

export function project(view: LeaderboardView, event: FeatureBranchEvent): LeaderboardView {
  switch (event.type) {
    case "FeatureBranchCreated": {
      const row: BranchStat = { name: event.name, pushes: 0, active: true };
      return { branches: { ...view.branches, [event.name]: row } };
    }
    case "FeatureBranchPushed": {
      const existing = view.branches[event.name] ?? { name: event.name, pushes: 0, active: true };
      const updated: BranchStat = { ...existing, pushes: existing.pushes + 1, lastPushAt: event.at };
      return { branches: { ...view.branches, [event.name]: updated } };
    }
    case "FeatureBranchRebased":
      return view;
    case "FeatureBranchDeleted": {
      const existing = view.branches[event.name];
      if (!existing) return view;
      return { branches: { ...view.branches, [event.name]: { ...existing, active: false } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
