```typescript
import { Effect } from "effect";

export type CodeReviewCommand =
  | { type: "request"; id: string; author: string; reviewers: string[] }
  | { type: "submit"; verdict: "approve" | "changes" };

export type CodeReviewEvent =
  | { type: "CodeReviewRequested"; id: string; author: string; reviewers: string[] }
  | { type: "CodeReviewSubmitted"; verdict: "approve" | "changes" };

export type CodeReviewState =
  | { status: "none" }
  | { status: "open"; id: string }
  | { status: "completed"; id: string; verdict: "approve" | "changes" };

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${streamName}`);
    this.name = "ConcurrencyConflict";
  }
}

export interface ReadResult<E> {
  readonly events: E[];
  readonly revision: bigint | "no_stream";
}

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
}

export const initialState: CodeReviewState = { status: "none" };

export function evolve(state: CodeReviewState, event: CodeReviewEvent): CodeReviewState {
  switch (event.type) {
    case "CodeReviewRequested":
      return { status: "open", id: event.id };
    case "CodeReviewSubmitted":
      if (state.status !== "open") return state;
      return { status: "completed", id: state.id, verdict: event.verdict };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: CodeReviewCommand, state: CodeReviewState): CodeReviewEvent[] {
  switch (command.type) {
    case "request":
      if (state.status !== "none") throw new Error("ALREADY_REQUESTED");
      return [{ type: "CodeReviewRequested", id: command.id, author: command.author, reviewers: command.reviewers }];
    case "submit":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "CodeReviewSubmitted", verdict: command.verdict }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export function handle(
  store: EventStore<CodeReviewEvent>,
  streamName: string,
  command: CodeReviewCommand,
): Effect.Effect<void, ConcurrencyConflict | Error> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(() => store.readStream(streamName));
    const state = loaded.events.reduce(evolve, initialState);
    const newEvents = decide(command, state);
    yield* Effect.tryPromise({
      try: () => store.appendToStream(streamName, newEvents, { expectedRevision: loaded.revision }),
      catch: (err) => (err instanceof ConcurrencyConflict ? err : new ConcurrencyConflict(streamName, loaded.revision)),
    });
  });
}
```

Load current revision, decide, then append with expectedRevision set to the observed revision. Convert the store's mismatch signal into a typed error at the boundary.

```typescript
export type PullRequestEvent = { type: "PullRequestOpened" | "PullRequestMerged"; data: Record<string, string> };

export interface EventStore {
  readStream(stream: string): Promise<{ events: PullRequestEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: PullRequestEvent[],
    opts: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextRevision: bigint; conflict: boolean }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string) {
    super(`concurrency conflict on ${streamName}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendWithOcc(
  store: EventStore,
  streamName: string,
  decideFn: (events: PullRequestEvent[]) => PullRequestEvent[],
): Promise<bigint> {
  const loaded = await store.readStream(streamName);
  const newEvents = decideFn(loaded.events);
  const result = await store.appendToStream(streamName, newEvents, { expectedRevision: loaded.revision });
  if (result.conflict) throw new ConcurrencyConflict(streamName);
  return result.nextRevision;
}
