import { Effect } from "effect";

export type BuildRunEvent = { type: string; at: string; [k: string]: unknown };

export interface EventStore {
  readStream(stream: string): Promise<{ events: BuildRunEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: BuildRunEvent[],
    opts: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<bigint>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string, public readonly expected: bigint | "no_stream" | "any") {
    super(`concurrency conflict on ${streamName}`);
    this.name = "ConcurrencyConflict";
  }
}

function appendOnce(
  store: EventStore,
  streamName: string,
  produce: (events: BuildRunEvent[]) => BuildRunEvent[],
): Effect.Effect<bigint, ConcurrencyConflict> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(() => store.readStream(streamName));
    const newEvents = produce(loaded.events);
    return yield* Effect.tryPromise({
      try: () => store.appendToStream(streamName, newEvents, { expectedRevision: loaded.revision }),
      catch: () => new ConcurrencyConflict(streamName, loaded.revision),
    });
  });
}

export function appendWithRetry(
  store: EventStore,
  streamName: string,
  produce: (events: BuildRunEvent[]) => BuildRunEvent[],
): Effect.Effect<bigint, ConcurrencyConflict> {
  return appendOnce(store, streamName, produce).pipe(
    Effect.catchTag("ConcurrencyConflict" as never, () => appendOnce(store, streamName, produce)),
  );
}
