  | { type: "PullRequestMerged"; id: string; at: string }
  | { type: "PullRequestClosed"; id: string; reason: string };

export interface DashboardView {
  readonly open: Record<string, { id: string; branch: string }>;
  readonly mergedCount: number;
  readonly closedCount: number;
}

export const emptyView: DashboardView = { open: {}, mergedCount: 0, closedCount: 0 };

export interface EventRecord<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventStoreReader<E> {
  readBatch(from: bigint, batchSize: number): Promise<EventRecord<E>[]>;
}

export interface ReadStore<V> {
  persist(view: V, upToRevision: bigint): Promise<void>;
}

export interface RebuildOptions<V, E> {
  readonly from: bigint;
  readonly batchSize: number;
  readonly project: (view: V, event: E) => V;
  readonly persist: (view: V, upToRevision: bigint) => Promise<void>;
}

export async function rebuild(
  reader: EventStoreReader<PullRequestEvent>,
  options: RebuildOptions<DashboardView, PullRequestEvent>,
): Promise<void> {
  let cursor = options.from;
  let view: DashboardView = emptyView;
  for (;;) {
    const batch = await reader.readBatch(cursor, options.batchSize);
    if (batch.length === 0) return;
    for (const record of batch) {
      view = options.project(view, record.event);
      cursor = record.revision + 1n;
    }
    await options.persist(view, cursor);
  }
}
