```typescript
export type PullRequestCommand = { type: "open"; id: string; branch: string } | { type: "merge"; id: string; at: string };
export type PullRequestEvent =
  | { type: "PullRequestOpened"; id: string; branch: string }
  | { type: "PullRequestMerged"; id: string; at: string };

export type PullRequestState = { status: "none" } | { status: "open"; id: string } | { status: "merged"; id: string };

export const initialState: PullRequestState = { status: "none" };

export function evolve(state: PullRequestState, event: PullRequestEvent): PullRequestState {
  switch (event.type) {
    case "PullRequestOpened":
      return { status: "open", id: event.id };
    case "PullRequestMerged":
      if (state.status !== "open") return state;
      return { status: "merged", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: PullRequestCommand, state: PullRequestState): PullRequestEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "none") throw new Error("ALREADY_OPEN");
      return [{ type: "PullRequestOpened", id: command.id, branch: command.branch }];
    case "merge":
      if (state.status !== "open") throw new Error("NOT_OPEN");
      return [{ type: "PullRequestMerged", id: command.id, at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ events: PullRequestEvent[]; revision: bigint | "no_stream" }>;
  appendToStream(stream: string, events: PullRequestEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface PullRequestRow {
  readonly id: string;
  readonly status: "open" | "merged";
}

export interface ReadStore {
  find(id: string): Promise<PullRequestRow | null>;
}

// The read store is eventually consistent with the event store: a projection
// subscription lags the command side by at most one event at a time.
export async function handleCommand(store: EventStore, streamName: string, command: PullRequestCommand): Promise<void> {
  const loaded = await store.readStream(streamName);
  const state = loaded.events.reduce(evolve, initialState);
  const events = decide(command, state);
  await store.appendToStream(streamName, events, { expectedRevision: loaded.revision });
}

export async function queryView(reads: ReadStore, id: string): Promise<PullRequestRow | null> {
  return reads.find(id);
}
