  | { type: "StartBuildRunQueued"; runId: string; commit: string }
  | { type: "PublishArtefactQueued"; id: string; commit: string }
  | { type: "NotifyBuildFailureQueued"; commit: string; reason: string };

export function react(event: DomainEvent): Command | null {
  switch (event.type) {
    case "PullRequestMerged":
      return { type: "StartBuildRun", runId: `run-${event.prId}`, commit: event.commit };
    case "BuildRunFinished":
      return { type: "PublishArtefact", id: event.artefactId, commit: event.commit };
    case "BuildRunFailed":
      return { type: "NotifyBuildFailure", commit: event.commit, reason: event.reason };
    case "ArtefactPublished":
      return null;
    case "CodeReviewRequested":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface EventStore {
  appendToStream(stream: string, events: CommandEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function dispatch(store: EventStore, streamName: string, event: DomainEvent, revision: bigint | "no_stream"): Promise<void> {
  const cmd = react(event);
  if (!cmd) return;
  const toEvent: CommandEvent =
    cmd.type === "StartBuildRun"
      ? { type: "StartBuildRunQueued", runId: cmd.runId, commit: cmd.commit }
      : cmd.type === "PublishArtefact"
        ? { type: "PublishArtefactQueued", id: cmd.id, commit: cmd.commit }
        : { type: "NotifyBuildFailureQueued", commit: cmd.commit, reason: cmd.reason };
  await store.appendToStream(streamName, [toEvent], { expectedRevision: revision });
}
