  | { type: "StartBuildRun"; prId: string }
  | { type: "TagCommitGreen"; commit: string };

export type CommandQueued =
  | { type: "StartBuildRunQueued"; prId: string }
  | { type: "TagCommitGreenQueued"; commit: string };

export function react(event: DomainEvent): Command | null {
  switch (event.type) {
    case "CodeReviewSubmitted":
      if (event.verdict !== "approve") return null;
      return { type: "StartBuildRun", prId: event.prId };
    case "BuildRunFinished":
      return { type: "TagCommitGreen", commit: event.commit };
    case "FeatureBranchPushed":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface EventStore {
  appendToStream(stream: string, events: CommandQueued[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function dispatch(store: EventStore, streamName: string, event: DomainEvent, revision: bigint | "no_stream"): Promise<void> {
  const cmd = react(event);
  if (!cmd) return;
  const queued: CommandQueued =
    cmd.type === "StartBuildRun"
      ? { type: "StartBuildRunQueued", prId: cmd.prId }
      : { type: "TagCommitGreenQueued", commit: cmd.commit };
  await store.appendToStream(streamName, [queued], { expectedRevision: revision });
