Open a transaction, insert outbox rows, appendToStream, commit. A separate worker polls the outbox and marks rows as published.

```typescript
export type PullRequestEvent =
  | { type: "PullRequestMerged"; id: string; at: string }
  | { type: "PullRequestClosed"; id: string; reason: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export interface TransactionalConnection {
  begin(): Promise<Transaction>;
}

export interface Transaction {
  appendToStream(stream: string, events: PullRequestEvent[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
  insertOutbox(rows: OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

// A separate worker polls unpublished outbox rows and marks publishedAt after delivery.
export async function appendWithOutbox(
  conn: TransactionalConnection,
  streamName: string,
  events: PullRequestEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<void> {
  const tx = await conn.begin();
  try {
    await tx.appendToStream(streamName, events, { expectedRevision });
    await tx.insertOutbox(outboxRows);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
```

Use a dedicated DomainError class (or a discriminated union of error classes) and throw from `decide` when invariants are violated. The handler translates the throw into an API error; `decide` stays pure.

```typescript
export type ChangeSetState =
  | { status: "none" }
  | { status: "draft"; id: string; files: number }
  | { status: "submitted"; id: string; files: number }
  | { status: "merged"; id: string };

export type ChangeSetCommand =
  | { type: "create"; id: string }
  | { type: "addFile" }
  | { type: "submit" }
  | { type: "merge"; at: string };

export type ChangeSetEvent =
  | { type: "ChangeSetCreated"; id: string }
  | { type: "ChangeSetFileAdded" }
  | { type: "ChangeSetSubmitted" }
  | { type: "ChangeSetMerged"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export function decide(command: ChangeSetCommand, state: ChangeSetState): ChangeSetEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new DomainError("ALREADY_EXISTS");
      return [{ type: "ChangeSetCreated", id: command.id }];
    case "addFile":
      if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
      return [{ type: "ChangeSetFileAdded" }];
    case "submit":
      if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
      if (state.files === 0) throw new DomainError("EMPTY_CHANGESET");
      return [{ type: "ChangeSetSubmitted" }];
    case "merge":
      if (state.status !== "submitted") throw new DomainError("NOT_SUBMITTED");
      return [{ type: "ChangeSetMerged", at: command.at }];
    default: {
      const _never: never = command;
      throw new DomainError("UNKNOWN_COMMAND");
    }
  }
}
