      return { status: "staged", id: event.id, version: event.version, envs: [] };
    case "RCPromoted":
      if (state.status !== "staged") return state;
      return { ...state, envs: [...state.envs, event.env] };
    case "RCBurned":
      if (state.status === "burned") return state;
      if (state.status === "none") return { status: "burned", id: "unknown", reason: event.reason };
      return { status: "burned", id: state.id, reason: event.reason };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: ReleaseCandidateEvent[]): ReleaseCandidateState {
  return events.reduce(evolve, initialState);
}
```

A pure reducer: `evolve(state, event) => newState`. Switch exhaustively on `event.type` and finish with a `never` guard. Wrap it in an `aggregate(events)` that calls `events.reduce(evolve, initialState)`.

```typescript
export type CommitEvent =
  | { type: "CommitRecorded"; sha: string; author: string; at: string }
  | { type: "CommitReverted"; sha: string; revertedBy: string; at: string };

export interface CommitState {
  readonly sha?: string;
  readonly author?: string;
  readonly recordedAt?: string;
  readonly reverted: boolean;
  readonly revertedBy?: string;
}

export const initialState: CommitState = { reverted: false };

export function evolve(state: CommitState, event: CommitEvent): CommitState {
  switch (event.type) {
    case "CommitRecorded":
      return { ...state, sha: event.sha, author: event.author, recordedAt: event.at };
    case "CommitReverted":
      if (!state.sha || state.sha !== event.sha) return state;
      return { ...state, reverted: true, revertedBy: event.revertedBy };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregate(events: CommitEvent[]): CommitState {
  return events.reduce(evolve, initialState);
}
